import java.io.*;
import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly handling user input by escaping it before outputting to an HTML file
        try {
            FileWriter writer = new FileWriter("output.html");
            writer.write("<html><body><h1>Welcome, " + Encode.forHtml(userInput) + "</h1></body></html>");
            writer.close();
            System.out.println("Output file created successfully.");
        } catch (IOException e) {
            System.out.println("Error writing to file: " + e.getMessage());
        }
    }
}

